import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Contest","description":"Engage your community and monetize your audience through operations funded by brands. Comprehensive guide to setup and GDPR compliance.","frontmatter":{"title":"Contest","description":"Engage your community and monetize your audience through operations funded by brands. Comprehensive guide to setup and GDPR compliance.","keywords":["contest","co-branded","leads","opt-in","gdpr","audience monetization"]},"headers":[],"relativePath":"en/publishers/co-branded-contest/index.md","filePath":"en/publishers/co-branded-contest/index.md"}'),s={name:"en/publishers/co-branded-contest/index.md"};function r(n,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="contest" tabindex="-1">Contest <a class="header-anchor" href="#contest" aria-label="Permalink to &quot;Contest&quot;">​</a></h1><p>Engage your community while monetizing your audience through operations funded by brands.</p><hr><h2 id="why-offer-this-format" tabindex="-1">Why offer this format? <a class="header-anchor" href="#why-offer-this-format" aria-label="Permalink to &quot;Why offer this format?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Media Revenue</strong><p>The advertiser funds everything — prizes, gifts, operational costs. 100% additional revenue source, risk-free for you.</p></div><div class="gi-value-card"><strong>🎉 Commercial Animation</strong><p>Offer a fun experience and attractive gifts to your customers. This boosts your site and newsletters.</p></div><div class="gi-value-card"><strong>📊 Data Qualification</strong><p>Reactivate inactive customers and collect highly qualified opt-in leads — qualified by the purchasing behavior of your own audience.</p></div></div><hr><h2 id="the-concept" tabindex="-1">The Concept <a class="header-anchor" href="#the-concept" aria-label="Permalink to &quot;The Concept&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You host a <strong>game page on your site</strong> (or a dedicated external page). You drive traffic to it via your usual channels (Email, Push, Social). The Advertiser retrieves the &quot;Opt-in&quot; leads at the end of the operation.</p></div><hr><h2 id="why-use-getinside" tabindex="-1">Why use getinside? <a class="header-anchor" href="#why-use-getinside" aria-label="Permalink to &quot;Why use getinside?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚖️ Legal Security</strong><p>Shared data collection is complex (GDPR). We provide legal notice templates and checkboxes validated by lawyers.</p></div><div class="gi-value-card"><strong>🤝 Prize Management</strong><p>You do not manage sending gifts to winners — the Advertiser takes care of it. Your responsibility ends with hosting the game.</p></div></div><hr><h2 id="setup-guide" tabindex="-1">Setup Guide <a class="header-anchor" href="#setup-guide" aria-label="Permalink to &quot;Setup Guide&quot;">​</a></h2><p>The technical and legal steps to launch a compliant contest.</p><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Landing Page (LP) Creation</h3><p>You are responsible for hosting the game to reassure your customer.</p><ul><li><strong>URL:</strong> On your domain (e.g., <code>your-site.com/brand-contest</code>).</li><li><strong>Design:</strong> Co-branded (Your usual header + the Advertiser&#39;s visual universe).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>The Form &amp; GDPR (Critical)</h3><p>To monetize the data (sell the lead to the advertiser), the form must strictly respect the GDPR.</p><div class="danger custom-block"><p class="custom-block-title">Mandatory notice — unchecked box</p><p>☐ <em>I agree to receive commercial offers from the partner [Advertiser Name].</em></p><p>⚠️ This box must <strong>NEVER</strong> be pre-checked.</p></div><pre><code>&lt;p&gt;&lt;em&gt;Note: Only participants checking this box will be billed to the Advertiser. The others play but are not monetizable.&lt;/em&gt;&lt;/p&gt;
</code></pre></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Activation Plan</h3><p>To guarantee the volume of leads (and therefore your revenue), activate your powerful channels:</p><ul><li><strong>📧 Dedicated Newsletter:</strong> &quot;Try to win XXX€ at [Brand]&quot;.</li><li><strong>🔔 Web Push Notification.</strong></li><li><strong>🖼️ Home Page Banners.</strong></li></ul></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Data Transfer</h3><p>At the end of the game:</p><ol><li>Export the list of participants <strong>with the partner opt-in</strong> (CSV/Excel).</li><li>Securely transmit the file to the Advertiser (via getinside).</li></ol><div class="tip custom-block"><p class="custom-block-title">Your work stops here</p><p>Once the file is transmitted, the advertiser integrates the leads into their CRM and <strong>immediately</strong> sends the welcome email with the promised consolation promo code. Speed is key to maximizing sales.</p></div></div></div>`,18)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
